package main

import (
    "fmt"
    "math"
    "strings"
)

func main() {
    // From fmt package
    fmt.Println("Hello from fmt!")

    // From math package
    fmt.Println("Pi:", math.Pi)
    fmt.Println("Sqrt of 16:", math.Sqrt(16))

    // From strings package
    msg := "hello world"
    fmt.Println("Uppercase:", strings.ToUpper(msg))
    fmt.Println("Contains 'world':", strings.Contains(msg, "world"))

