phase3.solution:
package main

import (
    "fmt"
    "math"
    "strings"
)

func main() {
    fmt.Println("Hello, World!")
    fmt.Println("Sqrt of 81:", math.Sqrt(81))
    fmt.Println("Lowercase:", strings.ToLower("GO IS GREAT"))
}
